import { chromium } from 'playwright';
import { writeFileSync } from 'fs';

const BASE_URL = 'https://nexus-ai-silk-six.vercel.app';
const SCREENSHOT_DIR = 'C:/Users/User/nexus-ai/test-screenshots';
const EMAIL = 'testuser@nexusai-test.com';
const PASSWORD = 'TestPassword123!';

const PAGES = [
  { name: 'Main Dashboard',     path: '/dashboard',                  file: '10-dashboard.png' },
  { name: 'Documents',          path: '/dashboard/documents',         file: '11-documents.png' },
  { name: 'Documents Upload',   path: '/dashboard/documents/upload',  file: '12-upload.png' },
  { name: 'Templates',          path: '/dashboard/templates',         file: '13-templates.png' },
  { name: 'Surveys',            path: '/dashboard/surveys',           file: '14-surveys.png' },
  { name: 'Create Survey',      path: '/dashboard/surveys/create',    file: '15-create-survey.png' },
  { name: 'Settings',           path: '/dashboard/settings',          file: '16-settings.png' },
  { name: 'Team Settings',      path: '/dashboard/settings/team',     file: '17-team.png' },
  { name: 'Billing Settings',   path: '/dashboard/settings/billing',  file: '18-billing.png' },
  { name: 'API Keys Settings',  path: '/dashboard/settings/api-keys', file: '19-api-keys.png' },
];

async function run() {
  const results = [];
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1440, height: 900 },
    ignoreHTTPSErrors: true,
  });
  const page = await context.newPage();

  // ---- STEP 1: LOGIN ----
  console.log('=== STEP 1: Navigating to login page ===');

  // Collect network errors globally
  const allNetworkErrors = {};

  page.on('response', (response) => {
    const status = response.status();
    if (status >= 400) {
      const url = response.url();
      if (!allNetworkErrors[page._currentPageKey]) {
        allNetworkErrors[page._currentPageKey] = [];
      }
      allNetworkErrors[page._currentPageKey].push({
        url,
        status,
        statusText: response.statusText(),
      });
    }
  });

  // Collect console errors globally
  const allConsoleErrors = {};
  page.on('console', (msg) => {
    if (msg.type() === 'error') {
      if (!allConsoleErrors[page._currentPageKey]) {
        allConsoleErrors[page._currentPageKey] = [];
      }
      allConsoleErrors[page._currentPageKey].push(msg.text());
    }
  });

  page._currentPageKey = 'login';

  try {
    await page.goto(`${BASE_URL}/login`, { waitUntil: 'networkidle', timeout: 30000 });
    console.log('Login page loaded. Current URL:', page.url());
  } catch (e) {
    console.log('Login page load warning:', e.message);
  }

  // Fill login form
  console.log('=== STEP 2: Filling login form ===');
  try {
    // Wait for form fields
    await page.waitForSelector('input[type="email"], input[name="email"], input[placeholder*="email" i]', { timeout: 10000 });

    // Try various selectors for email field
    const emailInput = await page.$('input[type="email"]')
      || await page.$('input[name="email"]')
      || await page.$('input[placeholder*="email" i]');

    if (emailInput) {
      await emailInput.fill(EMAIL);
      console.log('Email filled');
    } else {
      console.log('ERROR: Could not find email input');
    }

    // Try various selectors for password field
    const passwordInput = await page.$('input[type="password"]')
      || await page.$('input[name="password"]')
      || await page.$('input[placeholder*="password" i]');

    if (passwordInput) {
      await passwordInput.fill(PASSWORD);
      console.log('Password filled');
    } else {
      console.log('ERROR: Could not find password input');
    }

    // Click submit button
    const submitBtn = await page.$('button[type="submit"]')
      || await page.$('button:has-text("Sign in")')
      || await page.$('button:has-text("Log in")')
      || await page.$('button:has-text("Login")');

    if (submitBtn) {
      await submitBtn.click();
      console.log('Submit button clicked');
    } else {
      console.log('ERROR: Could not find submit button');
    }

    // Wait for navigation to dashboard
    console.log('=== STEP 3: Waiting for redirect to /dashboard ===');
    try {
      await page.waitForURL('**/dashboard**', { timeout: 15000 });
      console.log('Redirected to:', page.url());
    } catch (e) {
      console.log('Redirect timeout. Current URL:', page.url());
      // Try waiting a bit more
      await page.waitForTimeout(3000);
      console.log('After extra wait, URL:', page.url());
    }
  } catch (e) {
    console.log('Login error:', e.message);
  }

  // Take a brief pause to ensure session is stable
  await page.waitForTimeout(2000);
  console.log('Session stabilized. Current URL:', page.url());
  console.log('');

  // ---- STEP 2: VISIT EACH PAGE ----
  for (const pageInfo of PAGES) {
    const fullUrl = `${BASE_URL}${pageInfo.path}`;
    console.log(`=== Testing: ${pageInfo.name} (${fullUrl}) ===`);

    // Reset error collectors for this page
    page._currentPageKey = pageInfo.path;
    allNetworkErrors[pageInfo.path] = [];
    allConsoleErrors[pageInfo.path] = [];

    const result = {
      name: pageInfo.name,
      url: fullUrl,
      path: pageInfo.path,
      file: pageInfo.file,
      httpStatus: null,
      networkErrors: [],
      consoleErrors: [],
      description: '',
      error: null,
    };

    try {
      // Navigate to the page
      const response = await page.goto(fullUrl, {
        waitUntil: 'domcontentloaded',
        timeout: 30000
      });

      result.httpStatus = response ? response.status() : 'N/A';
      console.log(`  HTTP Status: ${result.httpStatus}`);

      // Wait for network to be mostly idle or at least 3 seconds
      try {
        await page.waitForLoadState('networkidle', { timeout: 10000 });
      } catch (e) {
        console.log('  networkidle timeout, waiting 3 extra seconds...');
        await page.waitForTimeout(3000);
      }

      // Additional wait for dynamic content
      await page.waitForTimeout(2000);

      // Check final URL (in case of redirects)
      const finalUrl = page.url();
      if (finalUrl !== fullUrl) {
        console.log(`  Redirected to: ${finalUrl}`);
        result.description += `Redirected to: ${finalUrl}. `;
      }

      // Try to fetch response bodies for network errors
      for (const err of allNetworkErrors[pageInfo.path]) {
        result.networkErrors.push(err);
      }

      // Collect console errors
      result.consoleErrors = [...(allConsoleErrors[pageInfo.path] || [])];

      // Get page title and some visible text for description
      const title = await page.title();
      result.description += `Title: "${title}". `;

      // Try to get main content description
      try {
        const heading = await page.$eval('h1, h2, [role="heading"]', el => el.textContent?.trim()).catch(() => null);
        if (heading) {
          result.description += `Main heading: "${heading}". `;
        }
      } catch (e) {
        // no heading found
      }

      // Check if page has visible content or shows an error
      try {
        const bodyText = await page.$eval('body', el => el.innerText?.substring(0, 500));
        if (bodyText && (bodyText.includes('404') || bodyText.includes('Not Found'))) {
          result.description += 'Page shows 404 Not Found. ';
        } else if (bodyText && (bodyText.includes('500') || bodyText.includes('Internal Server Error'))) {
          result.description += 'Page shows 500 Internal Server Error. ';
        } else if (bodyText && bodyText.includes('Error')) {
          const errorMatch = bodyText.match(/(?:Error|error)[^\n]{0,100}/);
          if (errorMatch) {
            result.description += `Error text found: "${errorMatch[0].trim()}". `;
          }
        }
      } catch (e) {
        // ignore
      }

      // Take full-page screenshot
      const screenshotPath = `${SCREENSHOT_DIR}/${pageInfo.file}`;
      await page.screenshot({
        path: screenshotPath,
        fullPage: true,
        timeout: 15000
      });
      console.log(`  Screenshot saved: ${screenshotPath}`);

    } catch (e) {
      result.error = e.message;
      console.log(`  ERROR: ${e.message}`);

      // Still try to take a screenshot even on error
      try {
        const screenshotPath = `${SCREENSHOT_DIR}/${pageInfo.file}`;
        await page.screenshot({ path: screenshotPath, fullPage: true });
        console.log(`  Error screenshot saved: ${screenshotPath}`);
      } catch (e2) {
        console.log(`  Could not take error screenshot: ${e2.message}`);
      }
    }

    // Log errors for this page
    if (result.networkErrors.length > 0) {
      console.log(`  Network errors (${result.networkErrors.length}):`);
      for (const err of result.networkErrors) {
        console.log(`    ${err.status} ${err.statusText} - ${err.url}`);
      }
    }
    if (result.consoleErrors.length > 0) {
      console.log(`  Console errors (${result.consoleErrors.length}):`);
      for (const err of result.consoleErrors) {
        console.log(`    ${err.substring(0, 200)}`);
      }
    }

    results.push(result);
    console.log('');
  }

  // ---- FINAL: Try to fetch response bodies for 4xx/5xx errors ----
  // We'll revisit pages with errors to capture response bodies
  console.log('\n=== CAPTURING ERROR RESPONSE BODIES ===');
  for (const result of results) {
    if (result.networkErrors.length > 0) {
      for (const err of result.networkErrors) {
        try {
          const resp = await page.request.get(err.url, { timeout: 5000 });
          const body = await resp.text();
          err.responseBody = body.substring(0, 500);
        } catch (e) {
          err.responseBody = `Could not fetch: ${e.message}`;
        }
      }
    }
  }

  await browser.close();

  // ---- SUMMARY ----
  console.log('\n\n========================================');
  console.log('       FULL TEST RESULTS SUMMARY');
  console.log('========================================\n');

  for (const r of results) {
    console.log(`--- ${r.name} ---`);
    console.log(`  URL: ${r.url}`);
    console.log(`  HTTP Status: ${r.httpStatus}`);
    console.log(`  Screenshot: ${r.file}`);
    console.log(`  Description: ${r.description}`);
    if (r.error) {
      console.log(`  Page Error: ${r.error}`);
    }
    if (r.networkErrors.length > 0) {
      console.log(`  Network Errors (${r.networkErrors.length}):`);
      for (const err of r.networkErrors) {
        console.log(`    [${err.status}] ${err.url}`);
        if (err.responseBody) {
          console.log(`      Body: ${err.responseBody.substring(0, 300)}`);
        }
      }
    } else {
      console.log('  Network Errors: None');
    }
    if (r.consoleErrors.length > 0) {
      console.log(`  Console Errors (${r.consoleErrors.length}):`);
      for (const err of r.consoleErrors) {
        console.log(`    ${err.substring(0, 300)}`);
      }
    } else {
      console.log('  Console Errors: None');
    }
    console.log('');
  }

  // Save results as JSON
  const jsonPath = `${SCREENSHOT_DIR}/dashboard-test-results.json`;
  writeFileSync(jsonPath, JSON.stringify(results, null, 2));
  console.log(`Full results saved to: ${jsonPath}`);
}

run().catch(e => {
  console.error('Fatal error:', e);
  process.exit(1);
});
